package com.example.agendacontactosgrhr.data.repository
import com.example.agendacontactosgrhr.data.local.dao.CropDao import com.example.agendacontactosgrhr.data.local.entity.CropEntity import com.example.agendacontactosgrhr.data.remote.datasource.ApiService import kotlinx.coroutines.flow.Flow import javax.inject.Inject import javax.inject.Singleton
@Singleton class CropRepository @Inject constructor( private val cropDao: CropDao, private val apiService: ApiService ) { fun obtenerTodosLosCultivos(): Flow<List<CropEntity>> = cropDao.obtenerTodosLosCultivos()
suspend fun insertarCultivos(cultivos: List<CropEntity>) = cropDao.insertarCultivos(cultivos)
suspend fun contarCultivos(): Int = cropDao.contarCultivos()
suspend fun obtenerCultivoPorId(id: Int): CropEntity? = cropDao.obtenerCultivoPorId(id)
fun obtenerFavoritos(): Flow<List<CropEntity>> = cropDao.obtenerFavoritos()
suspend fun actualizarFavorito(id: Int, isFav: Boolean) = cropDao.actualizarFavorito(id, isFav)
fun buscarPorNombre(query: String): Flow<List<CropEntity>> = cropDao.buscarPorNombre(query)
/** * Sincroniza los cultivos desde la API REST a la base de datos local. */ suspend fun syncCropsFromApi(): Result<Unit> { return try { val response = apiService.getCultivos() if (response.datos.isNotEmpty()) { val entities = response.datos.map { dto -> CropEntity( id = dto.id, nombre = dto.nombre, precioSemilla = dto.precioSemilla, precioVenta = dto.precioVenta, tiempoCrecimiento = dto.tiempoCrecimiento, tiempoRegreso = dto.tiempoRegreso ?: 0, temporada = dto.temporada ?: "Desconocida" ) } cropDao.insertarCultivos(entities) Result.success(Unit) } else { Result.failure(Exception("La API no devolvió datos")) } } catch (e: Exception) { Result.failure(e) } }
