                    contentDescription = if (npc.isFavorite) "Quitar de favoritos" else "Agregar a favoritos",
                    tint = if (npc.isFavorite) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
        }
    }
