val imageRes = drawableMap[crop.nombre.lowercase()] ?: com.example.agendacontactosgrhr.R.drawable.ic_launcher_background
Card( modifier = Modifier .fillMaxWidth() .clickable { navController.navigate("${Screens.DetailCrop.route}/${crop.id}") }, elevation = CardDefaults.cardElevation(defaultElevation = 2.dp) ) { Row( modifier = Modifier .padding(8.dp) .fillMaxWidth(), verticalAlignment = Alignment.CenterVertically ) { Image( painter = painterResource(id = imageRes), contentDescription = null, modifier = Modifier .size(50.dp) .clip(androidx.compose.foundation.shape.RoundedCornerShape(8.dp)), contentScale = ContentScale.Crop )
